import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"撤销订单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/cancel-order.md","filePath":"zh-CN/stock-trading/order-types/cancel-order.md"}'),i={name:"stock-trading/order-types/cancel-order.md"};function o(l,t,n,s,h,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="撤销订单" tabindex="-1">撤销订单 <a class="header-anchor" href="#撤销订单" aria-label="Permalink to &quot;撤销订单&quot;">​</a></h1><p>已提交但尚未完全成交的订单可以撤销。全部成交或已过期的订单无法撤销。</p><h2 id="撤销单笔订单" tabindex="-1">撤销单笔订单 <a class="header-anchor" href="#撤销单笔订单" aria-label="Permalink to &quot;撤销单笔订单&quot;">​</a></h2><ol><li>进入「资产」→「订单」→「待成交」</li><li>找到需要撤销的订单，点击进入订单详情</li><li>点击「撤单」，确认撤销</li></ol><p>撤销成功后，已占用的资金（买入委托）或股票（卖出委托）会立即释放回可用余额。</p><h2 id="批量撤销" tabindex="-1">批量撤销 <a class="header-anchor" href="#批量撤销" aria-label="Permalink to &quot;批量撤销&quot;">​</a></h2><p>在「待成交」订单列表页右上角，点击「全部撤单」可一次性撤销所有未成交订单。</p><h2 id="哪些订单可以撤销" tabindex="-1">哪些订单可以撤销 <a class="header-anchor" href="#哪些订单可以撤销" aria-label="Permalink to &quot;哪些订单可以撤销&quot;">​</a></h2><table tabindex="0"><thead><tr><th>订单类型</th><th>可撤销</th><th>说明</th></tr></thead><tbody><tr><td>限价单（未成交）</td><td>✓</td><td>随时可撤，交易时段内立即生效</td></tr><tr><td>限价单（部分成交）</td><td>✓</td><td>撤销后已成交部分保留，未成交部分取消</td></tr><tr><td>市价单</td><td>✗ 或极短窗口</td><td>提交后几乎即时成交，通常无法撤销</td></tr><tr><td>GTC / GTD 长期单</td><td>✓</td><td>可在任意交易日撤销</td></tr><tr><td>附加订单（止盈止损）</td><td>✓</td><td>在触发前可撤销</td></tr><tr><td>到价反弹订单</td><td>✓</td><td>触发前可撤销</td></tr><tr><td>网格交易</td><td>✓</td><td>停止网格后，未成交的子订单自动撤销</td></tr></tbody></table><p>GTC / GTD 订单在拆合股等公司行动发生时会被系统自动取消，详见<a href="/wiki/stock-trading/corporate-actions/impact-on-orders">长期订单影响</a>。</p><h2 id="不同时段撤单" tabindex="-1">不同时段撤单 <a class="header-anchor" href="#不同时段撤单" aria-label="Permalink to &quot;不同时段撤单&quot;">​</a></h2><p><strong>交易时段内</strong>：撤单请求实时发送至交易所，通常秒级完成。</p><p><strong>非交易时段</strong>：港股与美股订单可在非交易时段预挂，提交撤单后将在下一个交易时段开始时生效。</p><p><strong>港股开市竞价（09:00–09:20）</strong>：此时段内不支持撤单，须等竞价结束后才可撤销未成交订单。</p><h2 id="撤单后资金与持仓" tabindex="-1">撤单后资金与持仓 <a class="header-anchor" href="#撤单后资金与持仓" aria-label="Permalink to &quot;撤单后资金与持仓&quot;">​</a></h2><ul><li><strong>买入委托撤销</strong>：冻结的现金立即释放回账户可用余额</li><li><strong>卖出委托撤销</strong>：冻结的股票立即释放回可卖出股数</li><li>已成交部分不受影响，按原价格结算</li></ul><h2 id="撤单异常处理" tabindex="-1">撤单异常处理 <a class="header-anchor" href="#撤单异常处理" aria-label="Permalink to &quot;撤单异常处理&quot;">​</a></h2><p><strong>Q：撤单后显示「撤单中」持续很长时间怎么办？</strong><br> 港股交易时段内通常 30 秒内完成。如长时间未变更，可刷新订单列表。若仍异常，联系客服确认订单状态。</p><p><strong>Q：提交了市价单但想立即撤销，怎么办？</strong><br> 市价单会立即以当前最优价格成交，通常来不及撤销。建议改用限价单以便控制价格和撤单时机。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/order-types/limit-and-market">限价单与市价单</a> — 各订单类型特性与选择</li><li><a href="/wiki/stock-trading/trading-hours-and-rules/hk-trading-rules">港股交易规则与结算</a> — 交易时段与撤单规则</li><li><a href="/wiki/stock-trading/trading-hours-and-rules/us-trading-rules">美股交易规则与结算</a> — 美股交易特性</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/order-types">订单类型</a></li></ul>',23)])])}const g=a(i,[["render",o]]);export{p as __pageData,g as default};
